_____javascript
return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/src/gameLoop.js",
      value: `import { GRID_SIZE, CELL_SIZE, MOVE_INTERVAL } from "./config.js"

const lerp = (a, b, t) => a + (b - a) * t

export function createGameLoop({ snake, direction, onTick, onRender }) {
  let lastStep = performance.now()
  let accumulator = 0
  let prevSnake = snake.map(segment => ({ ...segment }))
  let currentSnake = snake.map(segment => ({ ...segment }))
  let animStart = performance.now()

  function setSnake(nextSnake) {
    prevSnake = currentSnake.map(segment => ({ ...segment }))
    currentSnake = nextSnake.map(segment => ({ ...segment }))
    animStart = performance.now()
  }

  function step(now) {
    const delta = now - lastStep
    lastStep = now
    accumulator += delta

    while (accumulator >= MOVE_INTERVAL) {
      accumulator -= MOVE_INTERVAL
      const nextSnake = onTick(currentSnake, direction)
      if (nextSnake) setSnake(nextSnake)
    }

    const t = Math.min(1, accumulator / MOVE_INTERVAL)
    const eased = t * t * (3 - 2 * t)

    const renderSnake = currentSnake.map((segment, i) => {
      const prev = prevSnake[i] || prevSnake[prevSnake.length - 1] || segment
      return {
        x: lerp(prev.x, segment.x, eased),
        y: lerp(prev.y, segment.y, eased)
      }
    })

    onRender(renderSnake)
    requestAnimationFrame(step)
  }

  requestAnimationFrame(step)
}
`
    }
  ]
})

