return await space.current.patchWidget("snake-game", {
  edits: [
    {
      // Smooth segment transitions by animating position changes between ticks.
      // This assumes the widget source uses a typical render/update loop with segment coords.
      find: /function\s+renderSnake\([\s\S]*?\n\}/,
      replace: `function renderSnake() {
  const cell = game.cellSize
  const t = Math.min(1, Math.max(0, game.moveProgress ?? 1))
  const ease = t * t * (3 - 2 * t)

  snake.forEach((segment, i) => {
    const prev = game.prevSnake?.[i] ?? segment
    const x = prev.x + (segment.x - prev.x) * ease
    const y = prev.y + (segment.y - prev.y) * ease

    const px = x * cell
    const py = y * cell
    const radius = cell * 0.22

    ctx.beginPath()
    ctx.fillStyle = i === 0 ? game.headColor : game.bodyColor
    ctx.roundRect(px + 2, py + 2, cell - 4, cell - 4, radius)
    ctx.fill()
  })
}`
    },
    {
      find: /game\.step\s*=\s*function\s*\(\)\s*\{[\s\S]*?\n\}/,
      replace: `game.step = function () {
  this.prevSnake = this.snake.map(s => ({ ...s }))
  this.moveProgress = 0

  // existing movement logic should update this.snake to its next grid positions here
  // the animation loop can then interpolate from prevSnake to snake
  const result = this._stepCore ? this._stepCore() : undefined
  const start = performance.now()
  const duration = 120

  const animate = (now) => {
    this.moveProgress = Math.min(1, (now - start) / duration)
    this.render()
    if (this.moveProgress < 1) requestAnimationFrame(animate)
  }
  requestAnimationFrame(animate)

  return result
}`
    }
  ]
})

